var textLengthValidation=function(){"use strict";return function(n,i){const t=n||"",l=t.length,m=t.trim()?t.trim().split(/\s+/).length:0;return i.valid?.minlength&&l<Number(i.valid.minlength)?"minlength":i.valid?.maxlength&&l>Number(i.valid.maxlength)?"maxlength":i.valid?.minword&&m<Number(i.valid.minword)?"minword":i.valid?.maxword&&m>Number(i.valid.maxword)?"maxword":""}}();
